    // Ray-cylinder intersection for hit detection
    bool ray_hits_player(const Vector3& origin, const Vector3& direction,
                         const Player& target, float max_range,
                         float& hit_distance, bool& is_headshot) {
        // Simplified: treat player as a vertical cylinder
        // Base at target.position, height = PLAYER_HEIGHT, radius = PLAYER_HIT_RADIUS

        // Project to XZ plane for cylinder check
        float dx = origin.x - target.position.x;
        float dz = origin.z - target.position.z;

        float a = direction.x * direction.x + direction.z * direction.z;
        float b = 2.0f * (dx * direction.x + dz * direction.z);
        float c = dx * dx + dz * dz - PLAYER_HIT_RADIUS * PLAYER_HIT_RADIUS;

        float discriminant = b * b - 4.0f * a * c;
        if (discriminant < 0) return false;

        float sqrt_disc = std::sqrt(discriminant);
        float t1 = (-b - sqrt_disc) / (2.0f * a);
        float t2 = (-b + sqrt_disc) / (2.0f * a);

        // Check both intersection points
        for (float t : {t1, t2}) {
            if (t < 0 || t > max_range) continue;

            float hit_y = origin.y + direction.y * t;
            float player_base_y = target.position.y;
            float player_top_y = target.position.y + PLAYER_HEIGHT;

            if (hit_y >= player_base_y && hit_y <= player_top_y) {
                hit_distance = t;
                is_headshot = (hit_y >= player_base_y + HEADSHOT_HEIGHT);
                return true;
            }
        }

        return false;
    }

    void handle_shoot(const ShootPacket* pkt, const sockaddr_in& sender) {
        std::string key = addr_key(sender);
        auto addr_it = address_to_player.find(key);
        if (addr_it == address_to_player.end()) return;

        uint32_t shooter_id = addr_it->second;
        auto shooter_it = players.find(shooter_id);
        if (shooter_it == players.end()) return;

        Player& shooter = shooter_it->second;
        if (!shooter.alive) return;

        // Process shot without validation as specified
        shooter.last_heartbeat = std::chrono::steady_clock::now();

        uint8_t weapon_id = pkt->weapon_id;
        if (weapon_id >= NUM_WEAPONS) weapon_id = 0;

        const WeaponDef& weapon = WEAPONS[weapon_id];
        shooter.current_weapon = weapon_id;

        Vector3 origin(pkt->origin_x, pkt->origin_y, pkt->origin_z);
        Vector3 direction(pkt->dir_x, pkt->dir_y, pkt->dir_z);
        direction = direction.normalized();

        // Find closest hit player
        float closest_dist = weapon.range;
        uint32_t hit_player_id = 0;
        bool headshot = false;

        for (auto& [pid, target] : players) {
            if (pid == shooter_id) continue;
            if (!target.alive) continue;

            float dist;
            bool hs;
            if (ray_hits_player(origin, direction, target, weapon.range, dist, hs)) {
                if (dist < closest_dist) {
                    closest_dist = dist;
                    hit_player_id = pid;
                    headshot = hs;
                }
            }
        }

        if (hit_player_id != 0) {
            Player& victim = players[hit_player_id];
            int damage = weapon.damage;
            if (headshot) {
                damage = static_cast<int>(damage * HEADSHOT_MULTIPLIER);
            }

            // Apply armor reduction
            if (victim.armor > 0) {
                int armor_absorb = std::min(victim.armor, damage / 2);
                victim.armor -= armor_absorb;
                damage -= armor_absorb;
            }

            victim.health -= damage;

            Vector3 hit_pos = origin + direction * closest_dist;

            std::cout << "[HIT] Player '" << shooter.name << "' hit '"
                      << victim.name << "' for " << damage << " damage"
                      << (headshot ? " (HEADSHOT)" : "")
                      << " | Victim HP: " << victim.health << std::endl;

            // Send hit notification to all
            HitNotificationPacket hit_notify;
            memset(&hit_notify, 0, sizeof(hit_notify));
            hit_notify.header.type = PACKET_HIT_NOTIFICATION;
            hit_notify.header.player_id = 0;
            hit_notify.header.sequence = state_sequence++;
            hit_notify.shooter_id = shooter_id;
            hit_notify.victim_id = hit_player_id;
            hit_notify.damage = static_cast<int16_t>(damage);
            hit_notify.remaining_health = static_cast<int16_t>(std::max(0, victim.health));
            hit_notify.hit_pos_x = hit_pos.x;
            hit_notify.hit_pos_y = hit_pos.y;
            hit_notify.hit_pos_z = hit_pos.z;
            broadcast_all(&hit_notify, sizeof(hit_notify));

            // Check for kill
            if (victim.health <= 0) {
                victim.health = 0;
                victim.alive = false;
                shooter.kills++;
                victim.deaths++;

                std::cout << "[KILL] Player '" << shooter.name << "' killed '"
                          << victim.name << "' with " << weapon.name
                          << " | K/D: " << shooter.kills << "/" << shooter.deaths
                          << std::endl;

                // Send kill notification
                KillNotificationPacket kill_notify;
                memset(&kill_notify, 0, sizeof(kill_notify));
                kill_notify.header.type = PACKET_KILL_NOTIFICATION;
                kill_notify.header.player_id = 0;
                kill_notify.header.sequence = state_sequence++;
                kill_notify.killer_id = shooter_id;
                kill_notify.victim_id = hit_player_id;
                kill_notify.weapon_id = weapon_id;
                broadcast_all(&kill_notify, sizeof(kill_notify));

                // Schedule respawn (handled in tick)
            }
        }

        // Update shooter's last shot time
        shooter.last_shot_time = std::chrono::steady_clock::now();
    }

